const ALLOWED_CONTENT_TYPES = ['application/json'];
const MAX_BODY_SIZE = 1024 * 100; // 100KB
const RATE_LIMIT_WINDOW = 60; // seconds
const RATE_LIMIT_MAX = 60; // requests per window

export default {
  async fetch(request, env, ctx) {
    try {
      const response = await handleRequest(request, env, ctx);
      return addSecurityHeaders(response, env);
    } catch (err) {
      console.error(`Unhandled error: ${err.message}`);
      return addSecurityHeaders(
        jsonResponse({ error: 'Internal Server Error' }, 500),
        env
      );
    }
  },
};

// --- Security Headers ---

function addSecurityHeaders(response, env) {
  const headers = new Headers(response.headers);
  headers.set('X-Content-Type-Options', 'nosniff');
  headers.set('X-Frame-Options', 'DENY');
  headers.set('X-XSS-Protection', '1; mode=block');
  headers.set('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
  headers.set('Content-Type', 'application/json');
  headers.set('Referrer-Policy', 'strict-origin-when-cross-origin');
  headers.set('Permissions-Policy', 'camera=(), microphone=(), geolocation=()');

  const allowedOrigin = env.ALLOWED_ORIGINS || '';
  headers.set('Access-Control-Allow-Origin', allowedOrigin);
  headers.set('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
  headers.set('Access-Control-Allow-Headers', 'Content-Type, Authorization');
  headers.set('Access-Control-Max-Age', '86400');

  return new Response(response.body, {
    status: response.status,
    statusText: response.statusText,
    headers,
  });
}

// --- Request Router ---

async function handleRequest(request, env, ctx) {
  if (request.method === 'OPTIONS') {
    return new Response(null, { status: 204 });
  }

  const url = new URL(request.url);

  // Validate origin
  const origin = request.headers.get('Origin');
  if (origin && origin !== env.ALLOWED_ORIGINS) {
    return jsonResponse({ error: 'Forbidden origin' }, 403);
  }

  // Rate limiting using Cloudflare KV (if available) or in-memory approximation
  const rateLimitResult = await checkRateLimit(request, env);
  if (!rateLimitResult.allowed) {
    return jsonResponse(
      { error: 'Rate limit exceeded. Try again later.' },
      429,
      { 'Retry-After': String(rateLimitResult.retryAfter) }
    );
  }

  // Stripe webhook endpoint (uses its own authentication via signature)
  if (url.pathname === '/webhooks/stripe' && request.method === 'POST') {
    return handleStripeWebhook(request, env);
  }

  // All other endpoints require API token authentication
  const authResult = authenticateRequest(request, env);
  if (!authResult.authenticated) {
    return jsonResponse({ error: 'Unauthorized' }, 401);
  }

  // Route to handlers
  switch (url.pathname) {
    case '/api/email/send':
      if (request.method !== 'POST') {
        return jsonResponse({ error: 'Method not allowed' }, 405);
      }
      return handleSendEmail(request, env);

    case '/api/payments/create-intent':
      if (request.method !== 'POST') {
        return jsonResponse({ error: 'Method not allowed' }, 405);
      }
      return handleCreatePaymentIntent(request, env);

    case '/api/payments/customers':
      if (request.method !== 'POST') {
        return jsonResponse({ error: 'Method not allowed' }, 405);
      }
      return handleCreateCustomer(request, env);

    case '/api/health':
      if (request.method !== 'GET') {
        return jsonResponse({ error: 'Method not allowed' }, 405);
      }
      return jsonResponse({ status: 'healthy', timestamp: new Date().toISOString() }, 200);

    default:
      return jsonResponse({ error: 'Not found' }, 404);
  }
}

// --- Authentication ---

function authenticateRequest(request, env) {
  const authHeader = request.headers.get('Authorization');
  if (!authHeader) {
    return { authenticated: false };
  }

  const parts = authHeader.split(' ');
  if (parts.length !== 2 || parts[0] !== 'Bearer') {
    return { authenticated: false };
  }

  const token = parts[1];

  // Constant-time comparison to prevent timing attacks
  if (!secureCompare(token, env.API_AUTH_TOKEN)) {
    return { authenticated: false };
  }

  return { authenticated: true };
}

function secureCompare(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') {
    return false;
  }
  if (a.length !== b.length) {
    return false;
  }

  const encoder = new TextEncoder();
  const bufA = encoder.encode(a);
  const bufB = encoder.encode(b);

  let result = 0;
  for (let i = 0; i < bufA.length; i++) {
    result |= bufA[i] ^ bufB[i];
  }
  return result === 0;
}

// --- Rate Limiting ---

async function checkRateLimit(request, env) {
  // Use Cloudflare KV for distributed rate limiting if available
  if (!env.RATE_LIMIT_KV) {
    // If KV not configured, allow (rely on Cloudflare's built-in protections)
    return { allowed: true };
  }

  const clientIP = request.headers.get('CF-Connecting-IP') || 'unknown';
  // Hash the IP to avoid storing raw IPs
  const ipHash = await hashValue(clientIP);
  const key = `ratelimit:${ipHash}`;

  try {
    const current = await env.RATE_LIMIT_KV.get(key, { type: 'json' });
    const now = Math.floor(Date.now() / 1000);

    if (!current) {
      await env.RATE_LIMIT_KV.put(
        key,
        JSON.stringify({ count: 1, windowStart: now }),
        { expirationTtl: RATE_LIMIT_WINDOW }
      );
      return { allowed: true };
    }

    if (now - current.windowStart >= RATE_LIMIT_WINDOW) {
      await env.RATE_LIMIT_KV.put(
        key,
        JSON.stringify({ count: 1, windowStart: now }),
        { expirationTtl: RATE_LIMIT_WINDOW }
      );
      return { allowed: true };
    }

    if (current.count >= RATE_LIMIT_MAX) {
      const retryAfter = RATE_LIMIT_WINDOW - (now - current.windowStart);
      return { allowed: false, retryAfter };
    }

    await env.RATE_LIMIT_KV.put(
      key,
      JSON.stringify({ count: current.count + 1, windowStart: current.windowStart }),
      { expirationTtl: RATE_LIMIT_WINDOW }
    );
    return { allowed: true };
  } catch (err) {
    // Fail open but log the error - don't block legitimate traffic due to KV issues
    console.error(`Rate limit check failed: ${err.message}`);
    return { allowed: true };
  }
}

async function hashValue(value) {
  const encoder = new TextEncoder();
  const data = encoder.encode(value);
  const hashBuffer = await crypto.subtle.digest('SHA-256', data);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map((b) => b.toString(16).padStart(2, '0')).join('');
}

// --- Input Validation ---

async function parseAndValidateBody(request) {
  const contentType = request.headers.get('Content-Type');
  if (!contentType || !ALLOWED_CONTENT_TYPES.some((ct) => contentType.includes(ct))) {
    throw new ValidationError('Content-Type must be application/json');
  }

  const contentLength = request.headers.get('Content-Length');
  if (contentLength && parseInt(contentLength, 10) > MAX_BODY_SIZE) {
    throw new ValidationError('Request body too large');
  }

  let body;
  try {
    const text = await request.text();
    if (text.length > MAX_BODY_SIZE) {
      throw new ValidationError('Request body too large');
    }
    body = JSON.parse(text);
  } catch (err) {
    if (err instanceof ValidationError) throw err;
    throw new ValidationError('Invalid JSON body');
  }

  if (typeof body !== 'object' || body === null || Array.isArray(body)) {
    throw new ValidationError('Request body must be a JSON object');
  }

  return body;
}

class ValidationError extends Error {
  constructor(message) {
    super(message);
    this.name = 'ValidationError';
  }
}

function validateEmail(email) {
  if (typeof email !== 'string') return false;
  // Strict email validation
  const emailRegex = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$/;
  return emailRegex.test(email) && email.length <= 254;
}

function sanitizeString(input, maxLength = 1000) {
  if (typeof input !== 'string') return '';
  return input.trim().slice(0, maxLength);
}

// --- SendGrid Email Handler ---

async function handleSendEmail(request, env) {
  let body;
  try {
    body = await parseAndValidateBody(request);
  } catch (err) {
    if (err instanceof ValidationError) {
      return jsonResponse({ error: err.message }, 400);
    }
    return jsonResponse({ error: 'Bad request' }, 400);
  }

  const { to, subject, text, html } = body;

  // Validate required fields
  if (!to || !subject || (!text && !html)) {
    return jsonResponse(
      { error: 'Missing required fields: to, subject, and either text or html' },
      400
    );
  }

  // Validate email
  if (!validateEmail(to)) {
    return jsonResponse({ error: 'Invalid email address' }, 400);
  }

  // Sanitize inputs
  const sanitizedSubject = sanitizeString(subject, 200);
  const sanitizedText = text ? sanitizeString(text, 10000) : undefined;
  const sanitizedHtml = html ? sanitizeString(html, 50000) : undefined;

  if (!sanitizedSubject) {
    return jsonResponse({ error: 'Subject cannot be empty' }, 400);
  }

  // Allowlist for sender domain (configure as needed)
  const fromEmail = 'noreply@yourdomain.com';
  const fromName = 'Your App';

  const sendgridPayload = {
    personalizations: [
      {
        to: [{ email: to }],
      },
    ],
    from: {
      email: fromEmail,
      name: fromName,
    },
    subject: sanitizedSubject,
    content: [],
  };

  if (sanitizedText) {
    sendgridPayload.content.push({ type: 'text/plain', value: sanitizedText });
  }
  if (sanitizedHtml) {
    sendgridPayload.content.push({ type: 'text/html', value: sanitizedHtml });
  }

  try {
    const sgResponse = await fetch('https://api.sendgrid.com/v3/mail/send', {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${env.SENDGRID_API_KEY}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(sendgridPayload),
    });

    if (sgResponse.status === 202) {
      return jsonResponse({ success: true, message: 'Email queued for delivery' }, 202);
    }

    // Don't leak SendGrid error details to the client
    const statusCode = sgResponse.status;
    console.error(`SendGrid API error: status=${statusCode}`);

    if (statusCode === 401) {
      console.error('SendGrid authentication failed - check API key configuration');
      return jsonResponse({ error: 'Email service configuration error' }, 502);
    }

    if (statusCode === 429) {
      return jsonResponse({ error: 'Email service rate limited. Try again later.' }, 429);
    }

    return jsonResponse({ error: 'Failed to send email' }, 502);
  } catch (err) {
    console.error(`SendGrid request failed: ${err.message}`);
    return jsonResponse({ error: 'Email service unavailable' }, 503);
  }
}

// --- Stripe Payment Intent Handler ---

async function handleCreatePaymentIntent(request, env) {
  let body;
  try {
    body = await parseAndValidateBody(request);
  } catch (err) {
    if (err instanceof ValidationError) {
      return jsonResponse({ error: err.message }, 400);
    }
    return jsonResponse({ error: 'Bad request' }, 400);
  }

  const { amount, currency, customer_id, metadata } = body;

  // Validate amount
  if (!amount || typeof amount !== 'number' || !Number.isInteger(amount) || amount < 50 || amount > 99999999) {
    return jsonResponse(
      { error: 'Amount must be an integer between 50 and 99999999 (in smallest currency unit)' },
      400
    );
  }

  // Validate currency - allowlist of supported currencies
  const allowedCurrencies = ['usd', 'eur', 'gbp', 'cad', 'aud', 'jpy'];
  const normalizedCurrency = typeof currency === 'string' ? currency.toLowerCase().trim() : '';
  if (!allowedCurrencies.includes(normalizedCurrency)) {
    return jsonResponse(
      { error: `Currency must be one of: ${allowedCurrencies.join(', ')}` },
      400
    );
  }

  // Validate customer_id if provided
  if (customer_id !== undefined) {
    if (typeof customer_id !== 'string' || !/^cus_[a-zA-Z0-9]{10,30}$/.test(customer_id)) {
      return jsonResponse({ error: 'Invalid customer_id format' }, 400);
    }
  }

  // Build Stripe request body
  const stripeParams = new URLSearchParams();
  stripeParams.append('amount', String(amount));
  stripeParams.append('currency', normalizedCurrency);
  stripeParams.append('automatic_payment_methods[enabled]', 'true');

  if (customer_id) {
    stripeParams.append('customer', customer_id);
  }

  // Sanitize and add metadata (limited to safe key-value pairs)
  if (metadata && typeof metadata === 'object' && !Array.isArray(metadata)) {
    const metadataKeys = Object.keys(metadata).slice(0, 20); // Stripe allows max 50, we limit to 20
    for (const key of metadataKeys) {
      const safeKey = sanitizeString(key, 40);
      const safeValue = sanitizeString(String(metadata[key]), 500);
      if (safeKey && safeValue) {
        stripeParams.append(`metadata[${safeKey}]`, safeValue);
      }
    }
  }

  try {
    const stripeResponse = await fetch('https://api.stripe.com/v1/payment_intents', {
      method: 'POST',
      headers: {
        Authorization: `Basic ${btoa(env.STRIPE_SECRET_KEY + ':')}`,
        'Content-Type': 'application/x-www-form-urlencoded',
        'Stripe-Version': '2023-10-16',
      },
      body: stripeParams.toString(),
    });

    const stripeData = await stripeResponse.json();

    if (!stripeResponse.ok) {
      console.error(`Stripe API error: type=${stripeData.error?.type}, code=${stripeData.error?.code}`);

      if (stripeResponse.status === 401) {
        console.error('Stripe authentication failed - check API key configuration');
        return jsonResponse({ error: 'Payment service configuration error' }, 502);
      }

      if (stripeResponse.status === 429) {
        return jsonResponse({ error: 'Payment service rate limited. Try again later.' }, 429);
      }

      // Return safe error message based on Stripe error type
      const safeMessage = getStripeErrorMessage(stripeData.error);
      return jsonResponse({ error: safeMessage }, 400);
    }

    // Return only necessary fields - never expose full Stripe response
    return jsonResponse({
      id: stripeData.id,
      client_secret: stripeData.client_secret,
      amount: stripeData.amount,
      currency: stripeData.currency,
      status: stripeData.status,
    }, 201);
  } catch (err) {
    console.error(`Stripe request failed: ${err.message}`);
    return jsonResponse({ error: 'Payment service unavailable' }, 503);
  }
}

// --- Stripe Customer Handler ---

async function handleCreateCustomer(request, env) {
  let body;
  try {
    body = await parseAndValidateBody(request);
  } catch (err) {
    if (err instanceof ValidationError) {
      return jsonResponse({ error: err.message }, 400);
    }
    return jsonResponse({ error: 'Bad request' }, 400);
  }

  const { email, name, description } = body;

  if (!email || !validateEmail(email)) {
    return jsonResponse({ error: 'Valid email is required' }, 400);
  }

  const stripeParams = new URLSearchParams();
  stripeParams.append('email', email);

  if (name) {
    stripeParams.append('name', sanitizeString(name, 200));
  }
  if (description) {
    stripeParams.append('description', sanitizeString(description, 500));
  }

  try {
    const stripeResponse = await fetch('https://api.stripe.com/v1/customers', {
      method: 'POST',
      headers: {
        Authorization: `Basic ${btoa(env.STRIPE_SECRET_KEY + ':')}`,
        'Content-Type': 'application/x-www-form-urlencoded',
        'Stripe-Version': '2023-10-16',
      },
      body: stripeParams.toString(),
    });

    const stripeData = await stripeResponse.json();

    if (!stripeResponse.ok) {
      console.error(`Stripe customer creation error: type=${stripeData.error?.type}`);

      if (stripeResponse.status === 401) {
        return jsonResponse({ error: 'Payment service configuration error' }, 502);
      }

      const safeMessage = getStripeErrorMessage(stripeData.error);
      return jsonResponse({ error: safeMessage }, 400);
    }

    return jsonResponse({
      id: stripeData.id,
      email: stripeData.email,
      name: stripeData.name,
      created: stripeData.created,
    }, 201);
  } catch (err) {
    console.error(`Stripe customer request failed: ${err.message}`);
    return jsonResponse({ error: 'Payment service unavailable' }, 503);
  }
}

// --- Stripe Webhook Handler ---

async function handleStripeWebhook(request, env) {
  const signature = request.headers.get('stripe-signature');
  if (!signature) {
    return jsonResponse({ error: 'Missing signature' }, 400);
  }

  let rawBody;
  try {
    rawBody = await request.text();
    if (rawBody.length > MAX_BODY_SIZE) {
      return jsonResponse({ error: 'Payload too large' }, 413);
    }
  } catch (err) {
    return jsonResponse({ error: 'Failed to read body' }, 400);
  }

  // Verify Stripe webhook signature
  const isValid = await verifyStripeSignature(rawBody, signature, env.STRIPE_WEBHOOK_SECRET);
  if (!isValid) {
    console.error('Stripe webhook signature verification failed');
    return jsonResponse({ error: 'Invalid signature' }, 401);
  }

  let event;
  try {
    event = JSON.parse(rawBody);
  } catch (err) {
    return jsonResponse({ error: 'Invalid JSON' }, 400);
  }

  // Validate event structure
  if (!event.type || !event.id || !event.data) {
    return jsonResponse({ error: 'Invalid event structure' }, 400);
  }

  // Allowlist of handled event types
  const handledEvents = [
    'payment_intent.succeeded',
    'payment_intent.payment_failed',
    'customer.subscription.created',
    'customer.subscription.updated',
    'customer.subscription.deleted',
    'invoice.paid',
    'invoice.payment_failed',
  ];

  if (!handledEvents.includes(event.type)) {
    // Acknowledge but don't process unhandled events
    return jsonResponse({ received: true, processed: false }, 200);
  }

  // Process the event (non-blocking)
  try {
    await processStripeEvent(event, env);
  } catch (err) {
    console.error(`Error processing Stripe event ${event.type}: ${err.message}`);
    // Still return 200 to prevent Stripe from retrying
    // Log for investigation
  }

  return jsonResponse({ received: true, processed: true }, 200);
}

async function verifyStripeSignature(payload, signatureHeader, secret) {
  try {
    const pairs = signatureHeader.split(',');
    let timestamp = null;
    const signatures = [];

    for (const pair of pairs) {
      const [key, value] = pair.trim().split('=');
      if (key === 't') {
        timestamp = value;
      } else if (key === 'v1') {
        signatures.push(value);
      }
    }

    if (!timestamp || signatures.length === 0) {
      return false;
    }

    // Reject timestamps older than 5 minutes to prevent replay attacks
    const currentTime = Math.floor(Date.now() / 1000);
    const tolerance = 300; // 5 minutes
    if (Math.abs(currentTime - parseInt(timestamp, 10)) > tolerance) {
      console.error('Stripe webhook timestamp outside tolerance window');
      return false;
    }

    const signedPayload = `${timestamp}.${payload}`;
    const encoder = new TextEncoder();

    const key = await crypto.subtle.importKey(
      'raw',
      encoder.encode(secret),
      { name: 'HMAC', hash: 'SHA-256' },
      false,
      ['sign']
    );

    const signatureBuffer = await crypto.subtle.sign('HMAC', key, encoder.encode(signedPayload));
    const expectedSignature = Array.from(new Uint8Array(signatureBuffer))
      .map((b) => b.toString(16).padStart(2, '0'))
      .join('');

    // Constant-time comparison
    return signatures.some((sig) => secureCompare(sig, expectedSignature));
  } catch (err) {
    console.error(`Signature verification error: ${err.message}`);
    return false;
  }
}

async function processStripeEvent(event, env) {
  switch (event.type) {
    case 'payment_intent.succeeded': {
      const paymentIntent = event.data.object;
      console.log(`Payment succeeded: ${paymentIntent.id}, amount: ${paymentIntent.amount}`);
      // Implement your business logic here
      // e.g., update order status, send confirmation email
      if (paymentIntent.receipt_email && validateEmail(paymentIntent.receipt_email)) {
        // Queue a confirmation email (fire and forget with error handling)
        try {
          await sendTransactionalEmail(
            env,
            paymentIntent.receipt_email,
            'Payment Confirmation',
            `Your payment of ${paymentIntent.amount / 100} ${paymentIntent.currency.toUpperCase()} has been received. Thank you!`
          );
        } catch (emailErr) {
          console.error(`Failed to send payment confirmation email: ${emailErr.message}`);
        }
      }
      break;
    }

    case 'payment_intent.payment_failed': {
      const failedIntent = event.data.object;
      console.log(`Payment failed: ${failedIntent.id}`);
      break;
    }

    case 'customer.subscription.created':
    case 'customer.subscription.updated':
    case 'customer.subscription.deleted': {
      const subscription = event.data.object;
      console.log(`Subscription ${event.type}: ${subscription.id}, status: ${subscription.status}`);
      break;
    }

    case 'invoice.paid': {
      const invoice = event.data.object;
      console.log(`Invoice paid: ${invoice.id}`);
      break;
    }

    case 'invoice.payment_failed': {
      const failedInvoice = event.data.object;
      console.log(`Invoice payment failed: ${failedInvoice.id}`);
      break;
    }

    default:
      break;
  }
}

// --- Helper: Send transactional email via SendGrid ---

async function sendTransactionalEmail(env, to, subject, textContent) {
  const payload = {
    personalizations: [{ to: [{ email: to }] }],
    from: { email: 'noreply@yourdomain.com', name: 'Your App' },
    subject: sanitizeString(subject, 200),
    content: [{ type: 'text/plain', value: sanitizeString(textContent, 10000) }],
  };

  const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${env.SENDGRID_API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(payload),
  });

  if (response.status !== 202) {
    throw new Error(`SendGrid returned status ${response.status}`);
  }
}

// --- Stripe Error Message Mapping ---

function getStripeErrorMessage(error) {
  if (!error || !error.type) {
    return 'Payment processing error';
  }

  switch (error.type) {
    case 'card_error':
      // Card errors can be shown to the user
      switch (error.code) {
        case 'card_declined':
          return 'Your card was declined';
        case 'expired_card':
          return 'Your card has expired';
        case 'incorrect_cvc':
          return 'Incorrect security code';
        case 'processing_error':
          return 'An error occurred while processing your card. Try again.';
        case 'insufficient_funds':
          return 'Insufficient funds';
        default:
          return 'Your card could not be processed';
      }
    case 'validation_error':
      return 'Invalid payment parameters';
    case 'rate_limit_error':
      return 'Too many requests. Please try again later.';
    case 'invalid_request_error':
      return 'Invalid payment request';
    case 'authentication_error':
    case 'api_connection_error':
    case 'api_error':
    default:
      // Never expose internal API errors
      return 'Payment processing error. Please try again.';
  }
}

// --- JSON Response Helper ---

function jsonResponse(data, status = 200, extraHeaders = {}) {
  const headers = new Headers({
    'Content-Type': 'application/json',
    ...extraHeaders,
  });

  return new Response(JSON.stringify(data), { status, headers });
}